/**
 * Initializes a new database connection from given parameters.
 * 
 * This function includes error checking to ensure all inputs are valid and returns proper error messages.
 * 
 * @return SUCCESS if connection attempt is successful, FAILURE otherwise.
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <libpq-fe.h>

#define SUCCESS 0
#define FAILURE 1

PGconn* initialize_db(const char* host, int port, const char* username, const char* password, const char* dbname) {
    // Initialize connection parameters
    PGconn* conn = PQconnectdb((char*)malloc(256 * sizeof(char)));
    if (conn == NULL) {
        if (PQerrorMessage(conn) != NULL) {
            free(PQerrorMessage(conn));
        }
        free(conn);
        return FAILURE;
    }

    // Check connection parameters
    if (host == NULL || port == 0 || username == NULL || password == NULL || dbname == NULL) {
        free(conn);
        return FAILURE;
    }

    if (strlen(host) == 0 || strlen(username) == 0 || strlen(password) == 0 || strlen(dbname) == 0) {
        free(conn);
        return FAILURE;
    }

    if (port < 0 || port > 65535) {
        free(conn);
        return FAILURE;
    }

    // Attempt connection
    if (PQconnectconn(conn) != 0) {
        free(conn);
        return FAILURE;
    }

    // Check connection status
    if (PQstatus(conn) != CONNECTION_OPENED) {
        PQfinish(conn);
        free(conn);
        return FAILURE;
    }

    free(conn);
    return SUCCESS;
}
