/**
 * Merges two pre-sorted arrays of integers into a single sorted array.
 *
 * This function takes two sorted arrays of integers as input, merges them into a single array, 
 * and returns the sorted result. The function uses efficient looping and condition handling to 
 * achieve merging with optimal runtime complexity, resulting in O(n + m) time complexity, 
 * where n and m are the sizes of the input arrays.
 *
 * @param arr1 The first sorted array of integers.
 * @param m The size of the first array.
 * @param arr2 The second sorted array of integers.
 * @param n The size of the second array.
 * @return A new sorted array containing all elements from both input arrays.
 */
#include <iostream>
#include <vector>

std::vector<int> mergeSortedArrays(const std::vector<int>& arr1, int m, const std::vector<int>& arr2, int n) {
    std::vector<int> result;
    int i = 0, j = 0;

    // Merge smaller elements first
    while (i < m && j < n) {
        if (arr1[i] < arr2[j]) {
            result.push_back(arr1[i]);
            i++;
        } else {
            result.push_back(arr2[j]);
            j++;
        }
    }

    // If there are remaining elements in arr1, append them to the result
    while (i < m) {
        result.push_back(arr1[i]);
        i++;
    }

    // If there are remaining elements in arr2, append them to the result
    while (j < n) {
        result.push_back(arr2[j]);
        j++;
    }

    return result;
}

int main() {
    std::vector<int> arr1 = {1, 3, 5, 7};
    int m = 4;
    std::vector<int> arr2 = {2, 4, 6, 8};
    int n = 4;

    std::vector<int> result = mergeSortedArrays(arr1, m, arr2, n);

    // Print the merged and sorted array
    for (int num : result) {
        std::cout << num << " ";
    }
    std::cout << std::endl;

    return 0;
}
