/// Merges two sorted arrays into a new sorted array.
///
/// # Parameters
///
/// * `arr1` - The first sorted array of integers.
/// * `arr2` - The second sorted array of integers.
///
/// # Return Value
///
/// A new sorted array that is a combination of `arr1` and `arr2`.
///
/// # Example
///
/// ```
/// let arr1 = [1, 3, 5, 7];
/// let arr2 = [2, 4, 6, 8];
///
/// let merged = merge_sorted_arrays(arr1, arr2);
/// assert_eq!(merged, [1, 2, 3, 4, 5, 6, 7, 8]);
/// ```rust
pub fn merge_sorted_arrays(arr1: Vec<i32>, arr2: Vec<i32>) -> Vec<i32> {
    let mut result = Vec::new();
    let mut i = 0;
    let mut j = 0;

    while i < arr1.len() && j < arr2.len() {
        if arr1[i] < arr2[j] {
            result.push(arr1[i]);
            i += 1;
        } else {
            result.push(arr2[j]);
            j += 1;
        }
    }

    result.extend_from_slice(&arr1[i..]);
    result.extend_from_slice(&arr2[j..]);

    result
}

