// CalculateInterest calculates compound interest for given principal amount, 
// interest rate, time period in years, and the number of times interest applied per year.
// 
// Parameters:
// principal float64 - The initial amount of money
// rate float64 - The interest rate as a decimal
// time float64 - The time period in years
// frequency int - The number of times interest applied per year
// 
// Returns:
// float64 - The compound interest
func CalculateInterest(principal float64, rate float64, time float64, frequency int) (float64, error) {
	// Validate input values
	if principal <= 0 {
		return 0, errors.New("principal must be greater than zero")
	}
	if rate < 0 || rate > 1 {
		return 0, errors.New("interest rate must be between 0 and 1")
	}
	if time < 0 {
		return 0, errors.New("time must be greater than or equal to zero")
	}
	if frequency <= 0 {
		return 0, errors.New("frequency must be greater than zero")
	}

	// Calculate compound interest
	interest := principal * (1 + rate/frequency) ^ (frequency*time) - principal

	return interest, nil
}

func main() {
	// Example usage:
	principal := 1000.0
.rate := 0.05
.time := 5.0
.frequency := 12

	interest, err := CalculateInterest(principal, rate, time, frequency)
	if err != nil {
		fmt.Println(err)
	} else {
		fmt.Printf("The compound interest is: $%.2f\n", interest)
	}
}
