// ProcessCSVData reads data from a given CSV file path and processes it based on provided conditions.
// The function takes two parameters: filePath string and processCondition string.
// The function error-checks the existence and readability of the file before proceeding with data processing.
// It processes the data based on the following conditions:
// - 'all': processes all rows in the CSV file.
// - 'invalid': processes only rows with invalid data.
// - 'valid': processes only rows with valid data.
package main

import (
	"encoding/csv"
	"fmt"
	"io"
	"os"
	"strings"
)

func ProcessCSVData(filePath string, processCondition string) ([][]string, error) {
	// Open the file in read mode.
	file, err := os.Open(filePath)
	if err != nil {
		return nil, fmt.Errorf("failed to open file: %w", err)
	}
	defer file.Close()

	// Read the CSV file.
	reader := csv.NewReader(file)
	data, err := reader.ReadAll()
	if err != nil {
		return nil, fmt.Errorf("failed to read CSV file: %w", err)
	}

	// Process the data based on the provided condition.
	switch processCondition {
	case "all":
		return data, nil
	case "invalid":
		var invalidRows [][]string
		for _, row := range data {
			if !isValidRow(row) {
				invalidRows = append(invalidRows, row)
			}
		}
		return invalidRows, nil
	case "valid":
		var validRows [][]string
		for _, row := range data {
			if isValidRow(row) {
				validRows = append(validRows, row)
			}
		}
		return validRows, nil
	default:
		return nil, fmt.Errorf("invalid process condition: %q", processCondition)
	}
}

// isValidRow checks if a row has valid data.
func isValidRow(row []string) bool {
	for _, value := range row {
		if !strings.Contains(value, ","), strings.Contains(value, "\t") {
			return false
		}
	}
	return true
}
