// This function compresses a given string by counting consecutive repeats of each character.
// If the compressed string is longer than the original, it returns the original string.
// Parameters:
// s (string): The input string to be compressed.
// Returns:
// string: The compressed string if it's shorter than the original, otherwise the original string.
func compressString(s string) string {
    if len(s) == 0 {
        return s
    }

    var compressed string
    var count int
    var currentChar rune = rune(s[0])

    for i := 1; i <= len(s); i++ {
        if i == len(s) || rune(s[i]) != currentChar {
            compressed += string(currentChar)
            if count > 1 {
                compressed += string(strconv.Itoa(count))
            }
            currentChar = rune(s[i])
            count = 1
        } else {
            count++
        }
    }

    if len(compressed) < len(s) {
        return compressed
    }

    return s
}
