//   - nums ([]int): A slice of integers.
// 
// Returns:
//   - (int64, error): The total sum as a 64-bit integer and an error if the sum exceeds the maximum value for integers in Go.
func SumSlice(nums []int) (int64, error) {
    // Initialize sum to 0
    var total int64

    // Iterate over each number in the slice
    for _, num := range nums {
        // Add the current number to the sum
        total += int64(num)

        // Check if the sum has overflowed
        if total > math.MaxInt64 {
            return 0, errors.New("integer overflow: sum exceeds the maximum value for integers in Go")
        }
    }

    // Return the sum and no error
    return total, nil
}
