import java.util.Stack;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

/**
 * Evaluates a mathematical expression in reverse Polish notation (RPN).
 * 
 * @param expression The mathematical expression in RPN.
 * @return The result of the evaluated expression.
 * @throws ArithmeticException if division by zero occurs.
 * @throws IllegalArgumentException if the expression is malformed.
 */
public class Main {
    public static double evaluateRPNExpression(String expression) throws ArithmeticException, IllegalArgumentException {
        // Split the expression into tokens (operators and operands)
        String[] tokens = expression.split("\\s+");

        // Create a stack to store operands
        Stack<Double> stack = new Stack<>();

        // Define the supported operators
        String[] operators = {"+", "-", "*", "/"};

        // Iterate through each token in the expression
        for (String token : tokens) {
            // Check if the token is an operator
            if (Pattern.compile("\\d+").matcher(token).find()) {
                // If the operator is not supported, throw an exception
                if (!isOperator(token)) {
                    throw new IllegalArgumentException("Malformed expression: unknown operator '" + token + "'");
                }

                // Check if there are enough operands on the stack
                if (stack.size() < 2) {
                    throw new IllegalArgumentException("Malformed expression: insufficient operands for operator '" + token + "'");
                }

                // Pop two operands from the stack
                double operand2 = stack.pop();
                double operand1 = stack.pop();

                // Evaluate the expression
                switch (token) {
                    case "+":
                        stack.push(operand1 + operand2);
                        break;
                    case "-":
                        stack.push(operand1 - operand2);
                        break;
                    case "*":
                        stack.push(operand1 * operand2);
                        break;
                    case "/":
                        if (operand2 == 0) {
                            throw new ArithmeticException("Division by zero");
                        }
                        stack.push(operand1 / operand2);
                        break;
                }
            } else {
                // Try to parse the token as an integer
                try {
                    stack.push(Double.parseDouble(token));
                } catch (NumberFormatException e) {
                    throw new IllegalArgumentException("Malformed expression: invalid operand '" + token + "'");
                }
            }
        }

        // Check if there is exactly one result left on the stack
        if (stack.size() != 1) {
            throw new IllegalArgumentException("Malformed expression: too many operands");
        }

        // Return the result
        return stack.pop();
    }

    private static boolean isOperator(String token) {
        for (String operator : operators) {
            if (operator.equals(token)) {
                return true;
            }
        }
        return false;
    }
}
